class Solution:
    def longestSubsequence(self, nums):
        n = len(nums)
        dp = [dict() for _ in range(n)]
        ans = 1
        for i in range(n):
            dp[i][None] = 1
            for j in range(i):
                diff = abs(nums[i] - nums[j])
                best_prev = 0
                for d, length in dp[j].items():
                    if d is None or d >= diff:
                        if length > best_prev:
                            best_prev = length
                if best_prev > 0:
                    cand = best_prev + 1
                    if cand > dp[i].get(diff, 0):
                        dp[i][diff] = cand
            ans = max(ans, max(dp[i].values()))
        return ans

