class Solution:
    def longestSubsequence(self, nums):
        V = 300
        START = V
        dp = [[0] * (V + 1) for _ in range(V + 1)]
        sfx = [[0] * (V + 2) for _ in range(V + 1)]
        ans = 0
        for x in nums:
            best_for_x = [0] * (V + 1)
            best_for_x[START] = 1
            for d in range(0, V):
                w1 = x - d
                w2 = x + d
                cand = 0
                if 1 <= w1 <= V:
                    cand = max(cand, sfx[w1][d] + 1)
                if w2 != w1 and 1 <= w2 <= V:
                    cand = max(cand, sfx[w2][d] + 1)
                if cand > best_for_x[d]:
                    best_for_x[d] = cand
            for d in range(0, V + 1):
                if best_for_x[d] > dp[x][d]:
                    dp[x][d] = best_for_x[d]
            running = 0
            for d in range(V, -1, -1):
                if dp[x][d] > running:
                    running = dp[x][d]
                sfx[x][d] = running
            ans = max(ans, sfx[x][0])
        return ans

