var longestSubsequence = function(nums) {
    const V = 300;
    const START = V;
    const dp = Array.from({ length: V + 1 }, () => new Array(V + 1).fill(0));
    const sfx = Array.from({ length: V + 1 }, () => new Array(V + 2).fill(0));
    let ans = 0;
    for (const x of nums) {
        const bestForX = new Array(V + 1).fill(0);
        bestForX[START] = 1;
        for (let d = 0; d < V; d++) {
            const w1 = x - d, w2 = x + d;
            let cand = 0;
            if (w1 >= 1 && w1 <= V) cand = Math.max(cand, sfx[w1][d] + 1);
            if (w2 !== w1 && w2 >= 1 && w2 <= V) cand = Math.max(cand, sfx[w2][d] + 1);
            if (cand > bestForX[d]) bestForX[d] = cand;
        }
        for (let d = 0; d <= V; d++) {
            if (bestForX[d] > dp[x][d]) dp[x][d] = bestForX[d];
        }
        let running = 0;
        for (let d = V; d >= 0; d--) {
            if (dp[x][d] > running) running = dp[x][d];
            sfx[x][d] = running;
        }
        ans = Math.max(ans, sfx[x][0]);
    }
    return ans;
};
